import React, { useMemo, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { bookingApi } from '../../api/bookingApi';
import ConflictWarning from './ConflictWarning';
import { ROOMS } from '../../utils/constants';
import { FiCalendar, FiClock, FiFileText, FiGrid, FiUsers, FiZap } from 'react-icons/fi';

const BookingForm = ({ onSuccess, onCancel }) => {
  const navigate = useNavigate();
  const [formData, setFormData] = useState({
    resourceId: '',
    resourceName: '',
    bookingDate: '',
    startTime: '',
    endTime: '',
    purpose: '',
    expectedAttendees: '',
  });
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);
  const [conflict, setConflict] = useState({ hasConflict: false, resourceName: '' });

  const minDateValue = useMemo(() => {
    const now = new Date();
    const local = new Date(now.getTime() - now.getTimezoneOffset() * 60000);
    return local.toISOString().slice(0, 10);
  }, []);

  const combineDateAndTime = (dateValue, timeValue) => {
    if (!dateValue || !timeValue) return null;

    const [year, month, day] = dateValue.split('-').map((part) => parseInt(part, 10));
    const [hour, minute] = timeValue.split(':').map((part) => parseInt(part, 10));

    if (
      Number.isNaN(year) ||
      Number.isNaN(month) ||
      Number.isNaN(day) ||
      Number.isNaN(hour) ||
      Number.isNaN(minute)
    ) {
      return null;
    }

    return new Date(year, month - 1, day, hour, minute, 0, 0);
  };

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData({ ...formData, [name]: value });
  };

  const handleDateChange = (date, field) => {
    setFormData({ ...formData, [field]: date });
  };

  const handleResourceChange = (e) => {
    const selectedId = parseInt(e.target.value, 10);
    const selectedRoom = ROOMS.find((room) => room.id === selectedId);

    if (!selectedRoom) {
      setFormData({ ...formData, resourceId: '', resourceName: '' });
      return;
    }

    setFormData({
      ...formData,
      resourceId: selectedRoom.id,
      resourceName: selectedRoom.name,
    });
  };

  const checkConflict = async (startDateTime, endDateTime) => {
    if (!formData.resourceId || !startDateTime || !endDateTime) return;

    try {
      const result = await bookingApi.checkConflict(
        formData.resourceId,
        startDateTime.toISOString(),
        endDateTime.toISOString()
      );
      setConflict({
        hasConflict: result.hasConflict,
        resourceName: formData.resourceName
      });
    } catch (err) {
      console.error('Error checking conflict:', err);
    }
  };

  const handleCheckAvailability = async () => {
    const startDateTime = combineDateAndTime(formData.bookingDate, formData.startTime);
    const endDateTime = combineDateAndTime(formData.bookingDate, formData.endTime);

    if (!startDateTime || !endDateTime) {
      setError('Please select a booking date and start/end time');
      return;
    }

    if (endDateTime <= startDateTime) {
      setError('End time must be after start time');
      return;
    }

    setError(null);
    await checkConflict(startDateTime, endDateTime);
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError(null);

    try {
      const startDateTime = combineDateAndTime(formData.bookingDate, formData.startTime);
      const endDateTime = combineDateAndTime(formData.bookingDate, formData.endTime);

      if (!startDateTime || !endDateTime) {
        setError('Please select a booking date and start/end time');
        return;
      }

      if (endDateTime <= startDateTime) {
        setError('End time must be after start time');
        return;
      }

      const expectedAttendeesValue =
        formData.expectedAttendees === '' || formData.expectedAttendees === null
          ? null
          : Number(formData.expectedAttendees);

      const bookingData = {
        resourceId: parseInt(formData.resourceId),
        resourceName: formData.resourceName,
        startTime: startDateTime.toISOString(),
        endTime: endDateTime.toISOString(),
        purpose: formData.purpose,
        expectedAttendees: Number.isNaN(expectedAttendeesValue) ? null : expectedAttendeesValue,
      };

      await bookingApi.createBooking(bookingData);
      if (typeof onSuccess === 'function') {
        onSuccess();
      } else {
        navigate('/bookings/success');
      }
    } catch (err) {
      setError(err.message || 'Failed to create booking');
    } finally {
      setLoading(false);
    }
  };

  return (
    <form className="booking-form" onSubmit={handleSubmit}>
      <div className="booking-form__header">
        <h2>Create New Booking</h2>
        <p>Reserve campus resources and schedule your next session.</p>
      </div>
      
      {error && <div className="error-message">{error}</div>}
      
      <ConflictWarning 
        hasConflict={conflict.hasConflict}
        resourceName={conflict.resourceName}
        startTime={combineDateAndTime(formData.bookingDate, formData.startTime) || new Date()}
        endTime={combineDateAndTime(formData.bookingDate, formData.endTime) || new Date()}
      />

      <div className="booking-form__card">
        <div className="booking-form__card-body">
          <div className="booking-form__grid booking-form__grid--3">
            <div className="form-group booking-form__span-3">
              <label className="booking-form__label">
                <FiGrid className="booking-form__label-icon" aria-hidden="true" />
                RESOURCE NAME
              </label>
              <select
                name="resourceName"
                value={formData.resourceId}
                onChange={handleResourceChange}
                required
              >
                <option value="">Select a room</option>
                {ROOMS.map((room) => (
                  <option key={room.id} value={room.id}>
                    {room.name} ({room.type})
                  </option>
                ))}
              </select>
              {formData.resourceId && (
                <small className="resource-id-hint">Room ID: {formData.resourceId}</small>
              )}
            </div>

            <div className="form-group">
              <label className="booking-form__label">
                <FiCalendar className="booking-form__label-icon" aria-hidden="true" />
                BOOKING DATE
              </label>
              <div className="booking-form__input-wrap">
                <input
                  type="date"
                  name="bookingDate"
                  value={formData.bookingDate}
                  min={minDateValue}
                  onChange={handleChange}
                  required
                />
                <span className="booking-form__input-icon" aria-hidden="true">
                  <FiCalendar />
                </span>
              </div>
            </div>

            <div className="form-group">
              <label className="booking-form__label">
                <FiClock className="booking-form__label-icon" aria-hidden="true" />
                START TIME
              </label>
              <div className="booking-form__input-wrap">
                <input
                  type="time"
                  name="startTime"
                  value={formData.startTime}
                  onChange={handleChange}
                  required
                />
                <span className="booking-form__input-icon" aria-hidden="true">
                  <FiClock />
                </span>
              </div>
            </div>

            <div className="form-group">
              <label className="booking-form__label">
                <FiClock className="booking-form__label-icon" aria-hidden="true" />
                END TIME
              </label>
              <div className="booking-form__input-wrap">
                <input
                  type="time"
                  name="endTime"
                  value={formData.endTime}
                  onChange={handleChange}
                  required
                />
                <span className="booking-form__input-icon" aria-hidden="true">
                  <FiClock />
                </span>
              </div>
            </div>

            <div className="form-group booking-form__span-2">
              <label className="booking-form__label">
                <FiUsers className="booking-form__label-icon" aria-hidden="true" />
                EXPECTED ATTENDEES
              </label>
              <input
                type="number"
                name="expectedAttendees"
                value={formData.expectedAttendees}
                onChange={handleChange}
                placeholder="Enter headcount"
                min="0"
              />
            </div>

            <div className="form-group booking-form__availability">
              <button
                type="button"
                className="booking-form__availability-btn"
                onClick={handleCheckAvailability}
                disabled={loading}
              >
                <FiZap aria-hidden="true" />
                Check Availability
              </button>
            </div>

            <div className="form-group booking-form__span-3">
              <label className="booking-form__label">
                <FiFileText className="booking-form__label-icon" aria-hidden="true" />
                PURPOSE OF BOOKING
              </label>
              <textarea
                name="purpose"
                value={formData.purpose}
                onChange={handleChange}
                required
                rows="4"
                placeholder="Briefly describe the event or session requirements..."
              />
            </div>
          </div>

          <div className="form-actions booking-form__actions">
            <button
              type="button"
              className="btn-cancel booking-form__btn-cancel"
              onClick={() => {
                if (typeof onCancel === 'function') {
                  onCancel();
                } else {
                  navigate('/bookings');
                }
              }}
            >
              Cancel
            </button>
            <button type="submit" className="btn-submit booking-form__btn-submit" disabled={loading}>
              {loading ? 'Creating...' : 'Create Booking'}
            </button>
          </div>
        </div>
      </div>
    </form>
  );
};

export default BookingForm;
